@app.call_tool()
async def call_tool(name: str, arguments: dict):
    ctx = app.request_context
    client_params = ctx.session.client_params

    # Check for sampling capability
    caps = getattr(client_params, "capabilities", None)
    has_sampling = caps is not None and getattr(caps, "sampling", None) is not None

    if name == "summarize":
        if not has_sampling:
            return [types.TextContent(
                type="text",
                text="Summarization requires sampling support. "
                     "Connect with a host that supports MCP sampling."
            )]

        text = arguments["text"]
        response = await ctx.session.create_message(
            messages=[
                types.SamplingMessage(
                    role="user",
                    content=types.TextContent(
                        type="text",
                        text=f"Summarize in one sentence:\n\n{text}"
                    )
                )
            ],
            max_tokens=100
        )
        return [types.TextContent(type="text", text=response.content.text)]

    raise ValueError(f"Unknown tool: {name}")

